/**
 * Menler AI Aptitude Test — question format:
 *   { q: '...', options: [{ t: '...', s: 1 }, ...] }
 *
 * SET-WISE QUESTIONS
 * ------------------
 * Add your questions per cluster + set in SET_QUESTIONS below.
 * Each cluster has 5 sets; each set should have 15 questions.
 *
 * Example:
 *   SET_QUESTIONS['Prompt Engineering'][0]  → Set 1
 *   SET_QUESTIONS['Prompt Engineering'][1]  → Set 2
 *
 * Clusters without an entry in SET_QUESTIONS fall back to APTITUDE_QUESTIONS
 * for every set (see aptitudeClusters.js).
 */

// Multiple-choice helper: `correct` is the 0-based index of the right option.
// The correct option scores 4 (max), distractors score 1 — so the existing
// score/recommendation/answer-sheet logic treats the right answer as "best".
const mc = (q, opts, correct) => ({
  q,
  options: opts.map((t, i) => ({ t, s: i === correct ? 4 : 1 })),
});

